#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int i=0;i<T;i++){
        long long N; scanf("%lld",&N);
        long long sum = N*(N+1)*(2*N+1)/6;
        if(i<T-1) printf("%lld\\n", sum);
        else printf("%lld", sum);
    }
    return 0;
}

